css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { min-height: 100vh; background: linear-gradient(160deg, #1e1b4b, #312e81, #1e1b4b); font-family: -apple-system, BlinkMacSystemFont, sans-serif; display: flex; align-items: center; justify-content: center; padding: 20px; }
.app { width: 100%; max-width: 520px; color: white; }
.quiz-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 16px; }
.category-tag { display: inline-block; background: rgba(99,102,241,0.3); border: 1px solid rgba(99,102,241,0.5); color: #a5b4fc; padding: 4px 12px; border-radius: 20px; font-size: 12px; font-weight: 700; margin-bottom: 4px; }
.question-num { font-size: 13px; color: rgba(255,255,255,0.5); }
.score-display { font-size: 14px; color: rgba(255,255,255,0.7); } .score-display strong { font-size: 24px; font-weight: 900; color: #a5b4fc; margin-left: 6px; }
.progress-bar { height: 6px; background: rgba(255,255,255,0.1); border-radius: 3px; margin-bottom: 24px; }
.progress-fill { height: 100%; border-radius: 3px; background: linear-gradient(90deg, #6366f1, #8b5cf6); transition: width 0.4s ease; }
.question-card { background: rgba(255,255,255,0.07); border: 1px solid rgba(255,255,255,0.12); border-radius: 24px; padding: 32px; position: relative; }
.timer-circle { position: absolute; top: 20px; right: 20px; width: 52px; height: 52px; } .timer-circle svg { width: 100%; height: 100%; } .timer-circle span { position: absolute; top: 50%; left: 50%; transform: translate(-50%,-50%); font-size: 14px; font-weight: 800; }
.question-emoji { font-size: 48px; margin-bottom: 16px; }
.question-card h2 { font-size: 20px; font-weight: 700; line-height: 1.4; margin-bottom: 24px; padding-right: 60px; }
.options { display: flex; flex-direction: column; gap: 12px; }
.option-btn { padding: 16px 20px; border-radius: 14px; border: 1px solid rgba(255,255,255,0.15); background: rgba(255,255,255,0.06); color: white; font-size: 15px; font-weight: 600; text-align: left; cursor: pointer; transition: all 0.2s; }
.option-btn:hover:not(:disabled) { border-color: #6366f1; background: rgba(99,102,241,0.15); }
.option-btn.correct { background: rgba(34,197,94,0.2); border-color: #22c55e; color: #86efac; }
.option-btn.wrong { background: rgba(239,68,68,0.2); border-color: #ef4444; color: #fca5a5; }
.result-screen { text-align: center; background: rgba(255,255,255,0.07); border: 1px solid rgba(255,255,255,0.12); border-radius: 24px; padding: 40px; }
.result-emoji { font-size: 64px; margin-bottom: 16px; }
.result-screen h2 { font-size: 32px; font-weight: 900; margin-bottom: 12px; }
.result-score { font-size: 72px; font-weight: 900; color: #a5b4fc; } .result-score small { font-size: 28px; color: rgba(255,255,255,0.5); }
.result-screen p { color: rgba(255,255,255,0.6); font-size: 16px; margin: 12px 0 24px; }
.result-stats { display: flex; justify-content: center; gap: 32px; margin-bottom: 28px; } .result-stats div { text-align: center; } .result-stats span { display: block; font-size: 12px; color: rgba(255,255,255,0.5); margin-bottom: 4px; } .result-stats strong { font-size: 24px; font-weight: 800; }
.restart-btn { padding: 16px 40px; border-radius: 16px; border: none; background: linear-gradient(135deg, #6366f1, #8b5cf6); color: white; font-size: 16px; font-weight: 800; cursor: pointer; }

