let current = 0, score = 0, correct = 0, wrong = 0, timerVal = 15, timerInterval, startTime;
function startQuiz() {
  current = 0; score = 0; correct = 0; wrong = 0;
  startTime = Date.now();
  document.getElementById('result').style.display = 'none';
  document.querySelector('.question-card').style.display = 'block';
  document.getElementById('score').textContent = 0;
  showQuestion();
}
function showQuestion() {
  clearInterval(timerInterval);
  if (current >= questions.length) { showResult(); return; }
  const q = questions[current];
  document.getElementById('q-num').textContent = 'Soru ' + (current+1) + '/' + questions.length;
  document.getElementById('q-emoji').textContent = q.emoji;
  document.getElementById('question').textContent = q.q;
  document.getElementById('progress').style.width = ((current/questions.length)*100) + '%';
  document.getElementById('options').innerHTML = q.opts.map((o,i) => `<button class='option-btn' onclick='answer(${i})'>${o}</button>`).join('');
  timerVal = 15;
  document.getElementById('timer').textContent = timerVal;
  const arc = document.getElementById('timer-arc');
  arc.style.stroke = '#6366f1';
  timerInterval = setInterval(() => {
    timerVal--;
    document.getElementById('timer').textContent = timerVal;
    const pct = (timerVal/15)*100;
    arc.setAttribute('stroke-dasharray', pct + ' ' + (100-pct));
    if (timerVal <= 5) arc.style.stroke = '#ef4444';
    if (timerVal <= 0) { clearInterval(timerInterval); wrong++; current++; setTimeout(showQuestion, 500); }
  }, 1000);
}
function answer(idx) {
  clearInterval(timerInterval);
  const q = questions[current];
  const btns = document.querySelectorAll('.option-btn');
  btns.forEach(b => b.disabled = true);
